#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_LINE 10005
#define MAX_STR 101
#define MAX_N 1000

int cmp_last_char(const void *a, const void *b){
    const char *s1 = *(const char **)a;
    const char *s2 = *(const char **)b;
    char c1 = s1[strlen(s1)-1];
    char c2 = s2[strlen(s2)-1];
    if(c1 < c2) return -1;
    if(c1 > c2) return 1;
    return 0;
}

int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    char line[MAX_LINE];
    fgets(line, sizeof(line), stdin); // consume end‑of‑line after T
    for(int tc=0; tc<T; ++tc){
        if(!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0'; // remove trailing newline
        char *tokens[MAX_N];
        int n=0;
        char *tok = strtok(line, " ");
        while(tok){
            tokens[n] = malloc(strlen(tok)+1);
            strcpy(tokens[n], tok);
            ++n;
            tok = strtok(NULL, " ");
        }
        qsort(tokens, n, sizeof(char*), cmp_last_char);
        for(int i=0;i<n;++i){
            printf("%s", tokens[i]);
            if(i+1<n) printf(" ");
            free(tokens[i]);
        }
        if(tc+1<T) printf("\n");
    }
    return 0;
}

