import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String first = br.readLine();
        if(first==null||first.isEmpty()) return;
        int T = Integer.parseInt(first.trim());
        StringBuilder out = new StringBuilder();
        for(int tc=0; tc<T; ++tc){
            String line = br.readLine();
            if(line==null) line="";
            String[] parts = line.trim().isEmpty()? new String[0] : line.trim().split(" +");
            Arrays.sort(parts, (a,b)->{
                char ca = a.charAt(a.length()-1);
                char cb = b.charAt(b.length()-1);
                return Character.compare(ca,cb);
            });
            for(int i=0;i<parts.length;++i){
                if(i>0) out.append(' ');
                out.append(parts[i]);
            }
            if(tc+1<T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
import sys

def sort_by_last_char(strings):
    return sorted(strings, key=lambda x: x[-1])

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out_lines = []
    for i in range(1, T+1):
        line = data[i] if i < len(data) else ''
        strings = line.split()
        sorted_strings = sort_by_last_char(strings)
        out_lines.append(' '.join(sorted_strings))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

